#include<bits/stdc++.h>
using namespace std;
#define inf INT_MAX;
#define mod 100003;
int v[1000005];
int d[1000005], n, m;
bool vis[1000005];
vector<int> e[1000005];
queue<int> q;
void init() {
	for (int i = 1; i <= n; i++) v[i] = inf;
	for (int i = 1; i <= n; i++) d[i] = 0;
	for (int i = 1; i <= n; i++) vis[i] = 0;
	d[1] = 1;
	v[1] = 0;
}
void bfs() {
	q.push(1);

	while (!q.empty()) {
		int x = q.front();
		vis[x] = 1;
		q.pop();
		for (int i = 0; i < e[x].size(); i++) {
			if (!vis[e[x][i]]) {
				if (v[e[x][i]] >= v[x] + 1) {
					if (v[e[x][i]] == INT_MAX) {

						q.push(e[x][i]);
					}
					v[e[x][i]] = v[x] + 1;
					d[e[x][i]] += d[x];
					d[e[x][i]] %= mod;
				}
			}
		}
	}
}
int main() {
	cin >> n >> m;
	init();
	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		e[x].push_back(y);
		e[y].push_back(x);
	}
	bfs();
	for (int i = 1; i <= n; i++) cout << d[i] << "\n";
	return 0;
}
